import companyData from './mock/compData.json'
import request from '@/utils/request'

export function getLoginHistory(param,isNotify) {
    let isTest = false
    let data = param
    return request({
      url: `/api/getLoginHistory`,
      meta: { apiVersion: '1.0.0' },
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      data : param,
      Notify: { use: isNotify, apitype: 'searched' } //searched, saved,deleted
    })
  }
  