<template>
    <v-container fluid fill-height align-start ma-0 pa-2>
      <v-row no-gutters>
        <v-layout row>
          <v-col cols="12" sm="12" lg="12" class="pa-2 pb-0">
            <i-card-top
              class="d-flex"
              :useBtnList="buttonUseList"
              @btnSearch="btnSearch()"
              @btnExcel="btnPrint()"
            >
              <template v-slot:body>
                <v-layout overflow-auto>
                  <v-row no-gutters class="pa-2">
                    <v-col cols="2">
                      <i-date-time-picker
                        :firstDisplayDate="startDate"
                        :dateOnly="true"
                        label="계획시작일자"
                        class="mx-1"
                        :allowMaxDate="endDate"
                        @getDate="setSearchDate($event, 'start')"
                      >
                      </i-date-time-picker>
                    </v-col>
                    <span class="pt-1">
                      ~
                    </span>
                    <v-col cols="2">
                      <i-date-time-picker
                        :firstDisplayDate="endDate"
                        :dateOnly="true"
                        label="계획종료일자"
                        class="mx-1"
                        :allowMinDate="startDate"
                        :allowMaxDate="currentDate"
                        @getDate="setSearchDate($event, 'end')"
                      >
                      </i-date-time-picker>
                    </v-col>
                  </v-row>
                </v-layout>
              </template>
            </i-card-top>
          </v-col>
          <v-col cols="12" sm="12" lg="12" class="pa-2 pt-0">
            <i-card-vertical headerTitle="로그인 이력 관리" device="web">
              <template v-slot:body>
                <v-layout column overflow-auto>
                  <v-col cols="12" md="12" class="row pa-0">
                    <v-col cols="12" class="pa-0">
                      <DxDataGrid
                        id="clientDataGrid"
                        class="layout-col-height00"
                        :ref="dxDataGridRef"
                        :data-source="data"
                        :remote-operations="false"
                        :hover-state-enabled="false"
                        :column-auto-width="true"
                        :show-borders="true"
                        :show-row-lines="true"
                        :selection="{ mode: 'none' }"
                        key-expr="loginSeq"
                        @editing-start="onEditingStart"
                      >
                        
                        <DxEditing mode="batch" :allow-updating="false" :select-text-on-edit-start="true" />
                        <DxSelection select-all-mode="allPages" show-check-boxes-mode="always" mode="multiple" />
  
                        <DxColumn data-field="compId" data-type="string" width="250px" alignment="left" caption="사업장번호" :hiding-priority="10" />
  
                        <DxColumn data-field="compNm" data-type="string" alignment="left" caption="사업장이름" :hiding-priority="9" />
  
                        <DxColumn data-field="userCd" data-type="string" width="100px" alignment="left" caption="유저코드" :hiding-priority="8" />
  
                        <DxColumn data-field="userNm" data-type="string" alignment="left" caption="성명" :hiding-priority="7" />
  
                        <DxColumn data-field="loginDate" data-type="string" alignment="left" caption="접속일시" :hiding-priority="6" /> 
  
                        <DxColumn data-field="loginIp" data-type="string" alignment="left" caption="IP" :hiding-priority="5"/>
  
                        <DxColumn data-field="loginDevice" data-type="string" alignment="center" caption="접속장치" :hiding-priority="4" />
  
                        <DxColumn data-field="loginSuccessYn" data-type="string" alignment="center" caption="접속성공 여부" :hiding-priority="4" :cell-template="renderLoginSuccessYnCell" />
                      </DxDataGrid>
  
                    </v-col>
                  </v-col>
                </v-layout>
              </template>
            </i-card-vertical>
          </v-col>
        </v-layout>
      </v-row>
    </v-container>
  </template>
  
  <script> 
  import iDateTimePicker from '@/components/common/iDateTimePicker.vue'
  import { getLoginHistory } from '@/api/setting/loginHistory'
  import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
  import BaseDataGrid from '@/views/base/BaseDataGrid.vue' //20220509 LYJ 데이타 그리드 사용시 베이스 추가
  import { getPreMonth } from '@/utils/common.js'
  import saveAs from 'file-saver'
  import { exportDataGrid } from 'devextreme/excel_exporter'
  import { Workbook } from 'exceljs'

  export default {
    mixins: [baseview, BaseDataGrid], //20220414 LYJ base page 추가
    components: {
        iDateTimePicker,
    },
    name: 'LoginHistoryManage',
    data() {
      return {
        pageSizes: [5],
        showPageSizeSelector: false,
        dxDataGridRef: 'clientDataGrid',
        data: [],
        buttonUseList: [
          'btnSearch', //조회
          'btnExcel' //삭제
        ],
        startDate: getPreMonth(1),
        endDate: getPreMonth(0),
        currentDate: getPreMonth(0),
        currentValue: '',
        postVisible: false
      }
    },
    computed: {},
    beforeMount() {},
    mounted() {
      this.btnSearch()
    },
    methods: {
      renderLoginSuccessYnCell(cellElement, cellInfo) {
        if (cellInfo.value === 'Y') {
          cellElement.innerHTML = '<span style="color: blue;">성공</span>';
        } else if (cellInfo.value === 'N') {
          cellElement.innerHTML = '<span style="color: red;">실패</span>';
        } else {
          cellElement.innerHTML = cellInfo.value;
        }
      },
      setSearchDate(e,param){
        if(param=='start'){
            this.startDate=e
        }else{
            this.endDate=e
        }
      },
      btnPrint(){
        const workbook = new Workbook()
        const worksheet = workbook.addWorksheet('InverterManage')

        function transformCellValue(cellInfo, column) {
            if (column.dataField === 'compId') {
            const compId = cellInfo.value
            const matchingComp = this.compList.find(comp => comp.compId === compId)
            return matchingComp ? matchingComp.compNm : '영농 단지'
            }
            return cellInfo.value
        }
        exportDataGrid({
            component: this.GetDataGrid(this.dxDataGridRef),
            worksheet,
            autoFilterEnabled: false,
            customizeCell: ({ gridCell, excelCell }) => {
            if (gridCell.column.dataField === 'loginSuccessYn') {
              if (gridCell.value === 'Y') {
                excelCell.font = { color: { argb: 'FF0000FF' } }; // 파란색
                excelCell.value = '성공';
              } else if (gridCell.value === 'N') {
                excelCell.font = { color: { argb: 'FFFF0000' } }; // 빨간색
                excelCell.value = '실패';
              }
            }
          }
        }).then(() => {
            workbook.xlsx.writeBuffer().then(buffer => {
            saveAs(new Blob([buffer], { type: 'application/octet-stream' }), 'LoginHistory.xlsx')
            })
        })
      },
      btnSearch() {
        this.openLoading('searching')
  
        this.data = []
        getLoginHistory({startDt:this.startDate.replaceAll('-',''),endDt:this.endDate.replaceAll('-','')},true)
          .then(res => {
            if (res.success) {
              this.gridInit(this.GetDataGrid(this.dxDataGridRef))
              this.data = res.list.map((item)=>{
                item.loginDate = item.loginDate.substring(0,19)
                return item
              })
              this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
            }
          })
          .catch(error => {})
          .finally(() => {
            this.endLoading()
          })
      },
      
    }
  }
  </script>
  
  <style lang="scss" scoped>
  ::v-deep .dx-box-item-content {
    height: 32px !important;
  }
  </style>
  